console.log("开始");

// setTimeout 是异步的（1秒后执行）
setTimeout(() => {
    console.log("1秒后");
}, 1000);

console.log("结束");

// 输出顺序：开始 → 结束 → 1秒后

// 创建一个 Promise
const fetchData = () => {
    return new Promise((resolve, reject) => {
        setTimeout(() => {
            const data = { name: "小明", score: 98 };
            resolve(data);      // 成功：传递结果
            // reject("网络错误");  // 失败：传递错误
        }, 1000);
    });
};

// 使用 .then() 处理成功，.catch() 处理失败
fetchData()
    .then(data => {
        console.log("获取成功：", data);
        return data.score * 2;  // 可以返回新值，传给下一个 .then
    })
    .then(doubled => console.log("双倍分数：", doubled))
    .catch(err => console.log("出错了：", err));

// 定义 async 函数
async function loadUserData(userId) {
    try {
        // await 等待 Promise 完成，就像「同步」一样
        const response = await fetch(`/api/users/${userId}`);
        const user = await response.json();
        console.log("用户信息：", user);
        return user;
    } catch (error) {
        console.error("加载失败：", error);
    }
}

// 调用 async 函数（它本身也是 Promise）
loadUserData(1).then(user => {
    console.log("姓名：", user.name);
});

// 或者在另一个 async 函数里 await
async function main() {
    const user = await loadUserData(1);
    console.log(user);
}

async function loadAll() {
    // ❌ 串行：总耗时 = 1s + 1s + 1s = 3s
    const a = await fetchA();
    const b = await fetchB();
    const c = await fetchC();

    // ✅ 并行：总耗时 ≈ max(1s, 1s, 1s) = 1s
    const [a, b, c] = await Promise.all([
        fetchA(),
        fetchB(),
        fetchC(),
    ]);

    console.log(a, b, c);
}

// Promise.allSettled：不管成功失败都等待所有完成
const results = await Promise.allSettled([p1, p2, p3]);
results.forEach(r => {
    if (r.status === 'fulfilled') console.log('成功', r.value);
    else console.log('失败', r.reason);
});
